body:
In the current implementation of `CoreToFSM`, the action region duplicates the logical
check from the guard region, despite the fact that we only execute the action region after checking if the 
guard region is true. At simulation time, this results in the logical check being done twice.

Here are some examples of where this inefficiency happens in the current implementation:

Verilog input:
```verilog
// Minimal FSM: state register + counter variable register.
// In state 0: if x, go to state 1 and increment counter.
// In state 1: go back to state 0 (counter unchanged).
//
// Expected: guard for 0->1 transition checks "x == 1",
// action should be just "counter <- counter + 1".
// Suspected inefficiency: action is "counter <- x ? counter+1 : counter".

module test_action_guard(
  input  logic       clk,
  input  logic       rst,
  input  logic       x,
  output logic [1:0] count
);
  logic       state;
  logic [1:0] counter;

  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state   <= 1'b0;
      counter <= 2'b00;
    end else begin
      case (state)
        1'b0: begin
          if (x) begin
            state   <= 1'b1;
            counter <= counter + 2'b01;
          end
        end
        1'b1: begin
          state   <= 1'b0;
        end
      endcase
    end
  end

  assign count = counter;
endmodule
```

Inefficient FSM output (original output):

```mlir
// /local/scratch/ak2518/circt/build/bin/circt-verilog /local/scratch/ak2518/circt/test_action_guard.sv | /local/scratch/ak2518/circt/build/bin/circt-opt  --hw-flatten-modules --hw-flatten-io --comb-assume-two-valued --arc-strip-sv=async-resets-as-sync --lower-ltl-to-core --canonicalize --convert-core-to-fsm
module {
  fsm.machine @test_action_guard(%arg0: i1, %arg1: i1) -> i2 attributes {initialState = "state_0"} {
    %counter = fsm.variable "counter" {initValue = 0 : i2} : i2
    fsm.state @state_0 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_1 guard {
        fsm.return %arg1
      } action {
        // counter := arg1 ? counter + 1 : counter
        %c1_i2 = hw.constant 1 : i2
        %0 = comb.add %counter, %c1_i2 : i2
        %1 = comb.mux bin %arg1, %0, %counter : i2
        fsm.update %counter, %1 : i2
      }
      fsm.transition @state_0 guard {
        %true = hw.constant true
        %0 = comb.xor %arg1, %true : i1
        fsm.return %0
      } action {
        // counter := arg1 ? counter + 1 : counter
        %c1_i2 = hw.constant 1 : i2
        %0 = comb.add %counter, %c1_i2 : i2
        %1 = comb.mux bin %arg1, %0, %counter : i2
        fsm.update %counter, %1 : i2
      }
    }
    fsm.state @state_1 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_0 guard {
        %true = hw.constant true
        fsm.return %true
      } action {
        fsm.update %counter, %counter : i2
      }
    }
  }
}
```

Efficient FSM output (new output):

```mlir
module {
  fsm.machine @test_action_guard(%arg0: i1, %arg1: i1) -> i2 attributes {initialState = "state_0"} {
    %counter = fsm.variable "counter" {initValue = 0 : i2} : i2
    fsm.state @state_0 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_1 guard {
        fsm.return %arg1
      } action {
        %c1_i2 = hw.constant 1 : i2
        %0 = comb.add %counter, %c1_i2 : i2
        fsm.update %counter, %0 : i2
      }
      fsm.transition @state_0 guard {
        %true = hw.constant true
        %0 = comb.xor %arg1, %true : i1
        fsm.return %0
      } action {
        fsm.update %counter, %counter : i2
      }
    }
    fsm.state @state_1 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_0 guard {
        %true = hw.constant true
        fsm.return %true
      } action {
        fsm.update %counter, %counter : i2
      }
    }
  }
}
```

Another Verilog Example:

```verilog
// Minimal FSM: state register + counter variable register.
// In state 0: if x, go to state 1 and increment counter.
// In state 1: go back to state 0 (counter unchanged).
//
// Expected: guard for 0->1 transition checks "x == 1",
// action should be just "counter <- counter + 1".
// Suspected inefficiency: action is "counter <- x ? counter+1 : counter".

module test_action_guard(
  input  logic       clk,
  input  logic       rst,
  input  logic [1:0]       x,
  output logic [1:0] count
);
  logic       state;
  logic [1:0] counter;

  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state   <= 1'b0;
      counter <= 2'b00;
    end else begin
      case (state)
        1'b0: begin
          if (x + 1 == 2) begin
            state   <= 1'b1;
            counter <= counter + 2'b01;
          end
        end
        1'b1: begin
          state   <= 1'b0;
        end
      endcase
    end
  end

  assign count = counter;
endmodule
```

inefficient output:
```fsm
module {
  fsm.machine @test_action_guard(%arg0: i1, %arg1: i2) -> i2 attributes {initialState = "state_0"} {
    %counter = fsm.variable "counter" {initValue = 0 : i2} : i2
    fsm.state @state_0 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_1 guard {
        %c0_i30 = hw.constant 0 : i30
        %c2_i32 = hw.constant 2 : i32
        %c1_i32 = hw.constant 1 : i32
        %0 = comb.concat %c0_i30, %arg1 : i30, i2
        %1 = comb.add %0, %c1_i32 : i32
        %2 = comb.icmp eq %1, %c2_i32 : i32
        fsm.return %2
      } action {
        // counter := x + 1 == 2 ? x + 1 : x
        %c0_i30 = hw.constant 0 : i30
        %c1_i2 = hw.constant 1 : i2
        %c2_i32 = hw.constant 2 : i32
        %c1_i32 = hw.constant 1 : i32
        %0 = comb.concat %c0_i30, %arg1 : i30, i2
        %1 = comb.add %0, %c1_i32 : i32
        %2 = comb.icmp eq %1, %c2_i32 : i32
        %3 = comb.add %counter, %c1_i2 : i2
        %4 = comb.mux bin %2, %3, %counter : i2
        fsm.update %counter, %4 : i2
      }
      fsm.transition @state_0 guard {
        %c0_i30 = hw.constant 0 : i30
        %c2_i32 = hw.constant 2 : i32
        %c1_i32 = hw.constant 1 : i32
        %0 = comb.concat %c0_i30, %arg1 : i30, i2
        %1 = comb.add %0, %c1_i32 : i32
        %2 = comb.icmp ne %1, %c2_i32 : i32
        fsm.return %2
      } action {
        %c0_i30 = hw.constant 0 : i30
        %c1_i2 = hw.constant 1 : i2
        %c2_i32 = hw.constant 2 : i32
        %c1_i32 = hw.constant 1 : i32
        %0 = comb.concat %c0_i30, %arg1 : i30, i2
        %1 = comb.add %0, %c1_i32 : i32
        %2 = comb.icmp eq %1, %c2_i32 : i32
        %3 = comb.add %counter, %c1_i2 : i2
        %4 = comb.mux bin %2, %3, %counter : i2
        fsm.update %counter, %4 : i2
      }
    }
    fsm.state @state_1 output {
      fsm.output %counter : i2
    } transitions {
      fsm.transition @state_0 guard {
        %true = hw.constant true
        fsm.return %true
      } action {
        fsm.update %counter, %counter : i2
      }
    }
  }
}
```

This PR fixes this inefficiency by replacing in the `action` region all expressions which are structurally equal to the `guard` region with `true`.
